INSERT INTO `products` (`id`, `server_id`, `category_id`, `image_url`, `name_ua`, `name_en`, `description_ua`, `description_en`, `price`, `duration_days`, `amx_access`, `amx_flags`, `model_te`, `model_ct`, `gender`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 1, 1, '', 'VIP 30 днів', 'VIP 30 Days', 'Броня + повний комплект гранати, Gold Deagle + Gold Knife, тег [VIP].\r\nМеню /ultimate з 5-ма комплектами зброї. \r\nНа старті 110 HP.  Max HP 120\r\nВампірік. \r\nСкін [VIP].\r\n\r\n', 'Armor + full set of grenades, Gold Deagle + Gold Knife, tag [VIP]\r\n/ultimate menu with 5 weapon loadouts.\r\n110 HP at spawn.  Max HP 120\r\nVampiric ability.\r\n[VIP] skin', 400.00, 30, 't', 'ce', '', '', '', 1, 1, '2026-03-03 20:22:48', '2026-04-02 16:40:23'),
(2, 1, 1, '', 'VIP 90 днів', 'VIP 90 Days', 'Все що у VIP 30 днів, але на 3 місяці. Економія 10%!\r\n\r\nБроня + повний комплект гранати, Gold Deagle + Gold Knife, тег [VIP].\r\nМеню /ultimate з 5-ма комплектами зброї. \r\nНа старті 110 HP.   Max HP 120\r\nВампірік. \r\nСкін [VIP].', 'Everything in VIP 30 Days, but for 3 months. Save 10%!\r\n\r\nArmor + full set of grenades, Gold Deagle + Gold Knife, tag [VIP]\r\n/ultimate menu with 5 weapon loadouts.\r\n110 HP at spawn.  Max HP 120\r\nVampiric ability.\r\n[VIP] skin', 1080.00, 90, 't', 'ce', '', '', '', 2, 1, '2026-03-03 20:22:48', '2026-04-02 16:40:33'),
(3, 1, 2, '', 'Адмін 30 днів', 'Admin 30 Days', 'Бан/кік, слей/заморозка, зміна карт, адмін-чат. Всі VIP привілеї включено.', 'Ban/kick, slay/freeze, map change, admin chat. All VIP privileges included.', 1000.00, 30, 'bcdeit', 'ce', '', '', '', 3, 0, '2026-03-03 20:22:48', '2026-03-26 09:02:47'),
(4, 1, 3, NULL, 'Розбан', 'Unban', 'Миттєве зняття бану та відновлення доступу до сервера.', 'Instant ban removal and access restoration to the server.', 500.00, 0, '', '', NULL, NULL, NULL, 4, 1, '2026-03-03 20:22:48', '2026-03-18 13:22:04'),
(5, 1, 4, 'https://cs-headshot.com/assets/images/vip_girl.jpg', 'Скін VIP Girl', 'Skin VIP Girl', 'Це стильний жіночий образ із поєднанням тактики та фентезі-естетики. Представлений у двох варіантах: темно-синій і насичений червоний. Корсет, високі чоботи та аксесуари додають виразності, а елементи екіпіровки підкреслюють бойовий характер і впевненість.', 'This skin features a stylish female design blending tactical and fantasy aesthetics. It comes in two variants: dark blue and deep red. The corset, high boots, and detailed accessories enhance the look, while the gear elements emphasize combat readiness and confidence.', 400.00, 30, 'vip_girl', '', 'vip_girl_te', 'vip_girl_ct', 'female', 5, 1, '2026-03-20 12:14:15', '2026-03-26 10:02:47'),
(6, 1, 4, 'https://cs-headshot.com/assets/images/vip_carrie.jpg', 'Скін VIP Carrie', 'Skin VIP Carrie', 'Унікальний тактичний образ із акцентом на мобільність і стиль. Представлений у двох варіантах: стриманий синій і яскравий червоний. Легка екіпіровка і пояс із підсумками підкреслюють баланс між швидкістю та бойовою готовністю, а сучасний дизайн додає елегантності.', 'This unique skin features a tactical design focused on mobility and style. It comes in two variants: a subtle blue and a bold red. Lightweight gear, a body armor vest, and utility pouches highlight the balance between speed and combat readiness, while the modern design adds a touch of elegance.', 400.00, 30, 'vip_carrie', '', 'vip_carrie_te', 'vip_carrie_ct', 'female', 5, 1, '2026-03-20 12:17:40', '2026-03-26 10:02:51'),
(7, 1, 4, 'https://cs-headshot.com/assets/images/vip_united.jpg', 'Скін VIP United', 'Skin VIP United', 'Персонаж у худі з маскою черепа та бронежилетом виглядає сучасно й загрозливо, з акцентом на контраст і ефект «енергії» по всій моделі.', 'The United skin features a dark tactical style with striking neon lines. It comes in two variants: cold blue and aggressive red. The character wears a hoodie, skull mask, and body armor, giving a modern and intimidating look with strong contrast and an “energy flow” effect across the model.', 400.00, 30, 'vip_united', '', 'vip_united_te', 'vip_united_ct', 'male', 8, 1, '2026-03-20 12:28:46', '2026-03-26 10:02:59'),
(8, 1, 4, 'https://cs-headshot.com/assets/images/vip_alice.jpg', 'Скін VIP Alice', 'Skin VIP Alice', 'Скін Alice — це ефектна довгонога блондинка з виразними татуюваннями та сміливим стилем. Образ поєднує елегантність і зухвалість  а деталі додають характеру. Доступна у двох кольорах — стриманому синьому та агресивному червоному, що підсилює контраст і робить модель помітною в грі.', 'Alice skin is a striking long-legged blonde with bold tattoos and a daring style. Her look blends elegance with audacity, while the details add personality. Available in two colors — a subtle blue and an aggressive red — enhancing contrast and making the model stand out in-game.', 400.00, 30, 'vip_alice', '', 'vip_alice_te', 'vip_alice_ct', 'female', 7, 1, '2026-03-20 13:54:55', '2026-03-26 10:02:55'),
(9, 1, 4, 'https://cs-headshot.com/assets/images/vip_furyghost.jpg', 'Скін VIP Лютий привид', 'Skin VIP FuryGhost', 'Темний тактичний боєць у стилі примари: маска приховує обличчя, а холодні відтінки та деталізоване спорядження створюють агресивний і загадковий образ. Модель виглядає сучасно й добре вписується в атмосферу CS 1.6, виділяючись серед стандартних скінів.', 'Dark tactical fighter with a ghost-like style: a masked face, cold tones, and detailed gear create an aggressive and mysterious look. The model feels modern and stands out clearly among standard CS 1.6 skins.', 400.00, 30, 'vip_furyghost', '', 'vip_furyghost_te', 'vip_furyghost_ct', 'male', 9, 1, '2026-03-20 15:47:59', '2026-03-31 10:47:40'),
(10, 1, 4, 'https://cs-headshot.com/assets/images/vip_spade.jpg', 'Скін VIP Spade', 'Skin VIP Spade', 'Spade («Лопата») — харизматичний боєць із зухвалим стилем: окуляри, татуйована рука та глибокий виріз додають образу бунтарського характеру. Контрастні кольори — червоний і синій — підкреслюють індивідуальність і роблять модель помітною в грі.', 'Spade is a charismatic fighter with a bold style: glasses, a tattooed arm, and a deep-cut outfit give him a rebellious edge. The contrasting red and blue variants highlight individuality and make the model stand out in-game.', 400.00, 30, 'vip_spade', '', 'vip_spade_te', 'vip_spade_ct', 'male', 10, 1, '2026-03-22 07:07:43', '2026-03-26 10:03:08'),
(11, 1, 4, 'https://cs-headshot.com/assets/images/vip_panda.jpg', 'Скін VIP Panda Boy', 'Skin VIP Panda Boy', 'Panda Boy — стильний міський боєць у худі з капюшоном-пандою та зловісною маскою. Контраст між милим образом і агресивною посмішкою створює унікальний вайб, а яскраві варіанти — синій і червоний — роблять модель добре помітною в грі.', 'Panda Boy is a stylish urban fighter wearing a panda hoodie and a sinister mask. The contrast between the cute look and the aggressive grin creates a unique vibe, while the blue and red variants make the model stand out in-game.', 400.00, 30, '', '', 'vip_panda_te', 'vip_panda_ct', 'male', 11, 1, '2026-03-22 19:00:17', '2026-03-26 10:03:12'),
(12, 1, 4, 'https://cs-headshot.com/assets/images/vip_helga.jpg', 'Скін VIP Helga', 'Skin VIP Helga', 'Helga — досвідчена бійчиня з холодним характером і впевненим стилем. Теплий светр, тактичне спорядження та стримані кольори створюють збалансований образ, що поєднує практичність і елегантність. Модель виглядає реалістично та добре читається в грі.', 'Helga is a seasoned fighter with a cold attitude and confident style. A warm sweater, tactical gear, and muted colors create a balanced look that blends practicality with elegance. The model feels realistic and stands out clearly in-game.', 400.00, 30, '', '', 'vip_helga_te', 'vip_helga_ct', 'female', 0, 1, '2026-03-24 16:16:00', '2026-03-26 10:02:42'),
(13, 1, 5, '', 'Буст XP', 'XP Boost', 'Подвійний досвід на 7 днів — піднімайся в рангу вдвічі швидше', 'Double XP for 7 days — rank up twice as fast', 150.00, 7, 't', 'ce', '', '', '', 12, 1, '2026-03-26 12:02:08', '2026-03-26 10:02:24'),
(14, 1, 6, '', 'VIP + Моделька', 'VIP + Model', 'VIP 30 днів + будь-яка моделька на вибір. Комбо-пропозиція!', 'VIP 30 days + any model of your choice. Combo deal!', 750.00, 30, 't', 'ce', '', '', '', 13, 1, '2026-03-26 12:02:08', '2026-03-26 10:02:37'),
(15, 1, 1, '', 'VIP 7 днів', 'VIP 7 Days', 'Спробуй наші віп привілегії на тиждень!\r\n\r\nБроня + повний комплект гранати, Gold Deagle + Gold Knife, тег [VIP].\r\nМеню /ultimate з 5-ма комплектами зброї. \r\nНа старті 110 HP.   Max HP 120\r\nВампірік. \r\nСкін [VIP].', 'Armor + full set of grenades, Gold Deagle + Gold Knife, tag [VIP]\r\n/ultimate menu with 5 weapon loadouts.\r\n110 HP at spawn.  Max HP 120\r\nVampiric ability.\r\n[VIP] skin', 100.00, 7, 't', 'ce', '', '', '', 0, 1, '2026-03-31 10:31:56', '2026-04-12 14:28:38'),
(16, 1, 4, 'https://cs-headshot.com/assets/images/sir_loudmouth.jpg', 'Скін  Кривавий Крикун', 'Skin Bloody Loudmouth', 'Sir Bloody Loudmouth («Сер Кривавий Крикун») — ексцентричний бійець у масці клоуна-демона з хижим оскалом та рогами. Шкіряний жилет із патронташем, бойові рукавиці та золотий ланцюг додають образу брутальної харизми. Контрастні варіанти — червоний і синій — підкреслюють його зухвалий і непередбачуваний характер на полі бою.', 'Sir Bloody Loudmouth is an eccentric fighter wearing a demonic clown mask with a predatory grin and horns. A leather vest with ammo straps, tactical gloves, and a gold chain add brutal charisma to the look. The contrasting red and blue variants emphasize his bold and unpredictable presence on the battlefield.', 800.00, 30, '', '', 'sir_loudmouth_te', 'sir_loudmouth_ct', 'male', 14, 1, '2026-03-31 10:50:28', '2026-03-31 10:50:28'),
(17, 1, 4, 'https://cs-headshot.com/assets/images/sir_silent.jpg', 'Скін Кривавий Мовчун', 'Skin Bloody Silent', 'Sir Bloody Silent  («Сер Кривавий Мовчун») — мовчазний найманець у шкіряній масці з хрестоподібним швом на роті, що підкреслює його холодний і безжальний характер. Костюм у тонку смужку, тактичний жилет із підсумками та золотий ланцюг створюють образ стильного гангстера, готового до бою. Червоний і синій варіанти додають контрасту та впізнаваності на полі бою.', 'Sir Bloody Silent Darryl is a silent mercenary in a leather mask with a cross-stitched mouth, emphasizing his cold and ruthless nature. A pinstripe suit, tactical vest with pouches, and a gold chain create the look of a stylish gangster ready for combat. The red and blue variants add contrast and instant recognition on the battlefield.', 800.00, 30, '', '', 'sir_silent_te', 'sir_silent_ct', 'male', 15, 1, '2026-03-31 12:26:59', '2026-03-31 12:26:59');
